// Allowlist of community-hub workflow names. Keep in sync with apps/automation/workflows/*.
// Failures from any workflow NOT in this list are silently dropped — defensive filter so
// unrelated workflows on the same n8n instance can't accidentally alert into our channel.
const ALLOWLIST = new Set([
  'security-scan',
  'scan-timeout-sweeper',
  'plugin-submission-received',
  'plugin-approved',
  'plugin-declined',
  'plugin-changes-requested',
  'template-submission-received',
  'template-approved',
  'template-declined',
  'cleanup-new-label-after-60d',
  'render-email (shared sub-workflow)',
]);

const payload = $input.first().json;
const name = payload?.workflow?.name;

if (!name || !ALLOWLIST.has(name)) {
  // Silently drop — return no items, downstream nodes don't run.
  return [];
}
return [{ json: payload }];

